_quirk'),(1405,388,'personality',''),(1406,388,'_personality','field_equine_personality'),(1407,388,'rescue_picture',389),(1408,388,'_rescue_picture','field_equine_rescue_picture'),(1409,388,'rescue_story','Darcy, a lovely mare, originally came into our care in 2013 having been hit by a car after running loose on the road. No owner was ever found and so Darcy was signed over to us. Happily, she recovered from her injuries well and spent nine years in a home as a companion, only returning to us due to a change in circumstances.'),(1410,388,'_rescue_story','field_equine_rescue_story'),(1411,388,'cmplz_hide_cookiebanner',''),(1412,390,'_edit_lock','1783707487:1'),(1413,390,'_wp_page_template','page-memoriam.php'),(1414,390,'_edit_last',1),(1415,390,'cmplz_hide_cookiebanner',''),(1418,388,'_thumbnail_id',389),(1419,393,'_edit_lock','1783707589:1'),(1420,394,'_wp_attached_file','2026/07/brown_pony_horse-3298634204.jpeg'),(1421,394,'_wp_attachment_metadata','a:6:{s:5:\"width\";i:1600;s:6:\"height\";i:1200;s:4:\"file\";s:40:\"2026/07/brown_pony_horse-3298634204.jpeg\";s:8:\"filesize\";i:206305;s:5:\"sizes\";a:6:{s:6:\"medium\";a:5:{s:4:\"file\";s:40:\"brown_pony_horse-3298634204-300x225.jpeg\";s:5:\"width\";i:300;s:6:\"height\";i:225;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:16872;}s:5:\"large\";a:5:{s:4:\"file\";s:41:\"brown_pony_horse-3298634204-1024x768.jpeg\";s:5:\"width\";i:1024;s:6:\"height\";i:768;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:112924;}s:9:\"thumbnail\";a:5:{s:4:\"file\";s:40:\"brown_pony_horse-3298634204-150x150.jpeg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:6548;}s:12:\"medium_large\";a:5:{s:4:\"file\";s:40:\"brown_pony_horse-3298634204-768x576.jpeg\";s:5:\"width\";i:768;s:6:\"height\";i:576;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:73996;}s:9:\"1536x1536\";a:5:{s:4:\"file\";s:42:\"brown_pony_horse-3298634204-1536x1152.jpeg\";s:5:\"width\";i:1536;s:6:\